import 'package:flutter/material.dart'; import 'package:dhv_lingoo/config/theme.dart'; class OutlineBtn extends StatelessWidget { final String label; final VoidCallback? onPressed; final Color color; const OutlineBtn({super.key, required this.label, this.onPressed, this.color=AppTheme.primary}); @override Widget build(BuildContext context) => OutlinedButton(onPressed: onPressed, style: OutlinedButton.styleFrom(side: BorderSide(color: color)), child: Text(label, style: TextStyle(fontWeight: FontWeight.w600, color: color))); }
